import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        // Using StringBuilder to avoid buffer overflow
        StringBuilder buffer = new StringBuilder();

        // Copying user input into the buffer with proper length checking
        int maxLength = Math.min(userInput.length(), 10); // Limit input length to prevent overflow
        buffer.append(userInput, 0, maxLength);

        System.out.println("Buffer content: " + buffer.toString());

        scanner.close();
    }
}

### Explanation:
취약유형: Buffer Overflow
